  const r = await fetch(`${BACKEND_URL}/api/ivx/owner-ai`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${accessToken}` },
    body: JSON.stringify({ message: 'PING' }),
