const EMAIL=env.IVX_OWNER_EMAIL.toLowerCase(); const PW=env.IVX_OWNER_PASSWORD;
const BACKEND='https://ivx-holdings-platform.onrender.com';
const API='https://api.ivxholding.com';
const ts=()=>new Date().toISOString();
const out={auditId:`live-deep-${Date.now()}`,timestamp:ts(),steps:[]};
const log=(k,v)=>{out.steps.push({step:k,...v});console.log(`[${ts()}] ${k}:`,JSON.stringify(v).slice(0,200));};

// 1. password grant (real Supabase session)
const gr=await fetch(`${SUPA}/auth/v1/token?grant_type=password`,{method:'POST',headers:{apikey:ANON,Authorization:`Bearer ${ANON}`,'Content-Type':'application/json'},body:JSON.stringify({email:EMAIL,password:PW})});
const gj=gr.ok?await gr.json():{};
log('passwordGrant',{ok:gr.ok,status:gr.status,hasToken:!!gj.access_token,expiresAt:gj.expires_at,userId:gj.user?.id,error:!gr.ok?(await gr.text()).slice(0,150):null});
const tok=gj.access_token;

// 2. backend auth diagnostic (deployed endpoint)
if(tok){const r=await fetch(`${BACKEND}/api/ivx/owner-ai/auth-diagnostic`,{headers:{Authorization:`Bearer ${tok}`}});
const j=r.ok?await r.json():{};
log('authDiagnostic',{ok:r.ok,status:r.status,accepted:j.accepted,ownerEmailAllowlisted:j.ownerEmailAllowlisted,supabaseUserFound:j.supabaseUserFound,tokenExpired:j.tokenExpired,rootCause:j.rootCause});}

// 3. owner-AI chat with real message
if(tok){const r=await fetch(`${BACKEND}/api/ivx/owner-ai`,{method:'POST',headers:{'Content-Type':'application/json',Authorization:`Bearer ${tok}`},body:JSON.stringify({message:'Say ALIVE if you can hear me'})});
const j=r.ok?await r.json():{};
log('ownerAIChat',{ok:r.ok,status:r.status,answer:j.answer?.slice(0,80),model:j.model,conversationId:j.conversationId,status2:j.status});}

// 4. backend health + deploy commit
const h=await fetch(`${API}/health`);const hj=h.ok?await h.json():{};
log('backendHealth',{ok:h.ok,status:h.status,healthy:hj.status,commit:hj.commit,bootTime:hj.bootTime,routeCount:(hj.routes||[]).length});

// 5. passwordless route exists on this deploy?
const p=await fetch(`${BACKEND}/api/ivx/owner-passwordless-login`,{method:'OPTIONS'});
log('passwordlessRouteDeployed',{status:p.status,exists:p.status!==404});

// 6. Render deploy status
const rd=await fetch(`https://api.render.com/v1/services/${env.RENDER_SERVICE_ID}`,{headers:{Authorization:`Bearer ${env.RENDER_API_KEY}`}});
const rdj=rd.ok?await rd.json():{};
log('renderService',{ok:rd.ok,name:rdj.name,status:rdj.status,id:rdj.id,suspended:rdj.suspended});

// 7. GitHub main vs local HEAD
import { execSync } from 'node:child_process';
const localSha=execSync('git rev-parse HEAD').toString().trim().slice(0,7);
const ghSha=execSync('git rev-parse github/main').toString().trim().slice(0,7);
log('gitState',{localHEAD:localSha,githubMain:ghSha,ahead:localSha!==ghSha});

const verdict=(gj.access_token&&hj.status==='healthy')?'OWNER_APPROVED_LIVE_AND_AI_REACHABLE':'INCOMPLETE';
out.verdict=verdict;
out.summary={
  supabaseOwner:EMAIL,
  sessionIssued:!!gj.access_token,
  backendCommit:hj.commit,
  backendHealthy:hj.status==='healthy',
  chatReachable:out.steps.find(s=>s.step==='ownerAIChat')?.ok,
  passwordlessDeployed:out.steps.find(s=>s.step==='passwordlessRouteDeployed')?.status!==404,
  localAheadOfGitHub:localSha!==ghSha,
  renderLive:rd.ok&&!rdj.suspended,
};
out.secretValuesReturned=false;
mkdirSync('backend/verification-proof',{recursive:true});
const path=`backend/verification-proof/live-owner-e2e-${out.auditId}.json`;
writeFileSync(path,JSON.stringify(out,null,2));
console.log('\n=== VERDICT ===');console.log(verdict);
console.log('=== SUMMARY ===');console.log(JSON.stringify(out.summary,null,2));
console.log(`proof: ${path}`);
JS
node /tmp/live-deep-audit.mjs 2>&1"}

